import React, { Fragment } from "react";
import "./App.css";
import { Container, Grid } from "@material-ui/core";
import Header from "./comp/Header.js";
import Body from "./comp/Body.js";

function App() {
  return (
    <Container maxWidth="xl">
      <Grid>
        <Header />
        <Body />

      </Grid>
    </Container>
  );
}

const Home = () => (
  <Fragment>
    <h1>Home</h1>
  </Fragment>
);

const About = () => (
  <Fragment>
    <h1>About</h1>
  </Fragment>
);

const Contact = () => (
  <Fragment>
    <h1>Contact</h1>
  </Fragment>
);

export default App;
